using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

class PropertyEditor : UITypeEditor
{
    public override object EditValue(
        System.ComponentModel.ITypeDescriptorContext context,
        IServiceProvider provider,
        object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null) return value;

        Control dropdown = CreateDropDown(value);

        // .NET 9: DropDownControl now throws ArgumentNullException for null.
        // Guard against null before calling.
        if (dropdown != null)
        {
            editorService.DropDownControl(dropdown);
            value = GetValueFromDropDown(dropdown);
        }

        return value;
    }

    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    private static Control CreateDropDown(object currentValue) => new ListBox();
    private static object GetValueFromDropDown(Control dropdown) => ((ListBox)dropdown).SelectedItem;
}

